def gen(rng, size):
    n = max(2, min(size, 100000))
    nums = []
    while len(nums) < n:
        choice = rng.random()
        base = rng.randint(1, 1000)
        if choice < 0.4:
            nums.extend([base, base])
        elif choice < 0.7:
            nums.extend([base, base, base])
        elif choice < 0.9:
            nums.extend([base, base + 1, base + 2])
        else:
            nums.append(base)
    return [nums[:n]]

