class Solution:
    def validPartition(self, nums):
        n = len(nums)
        dp = [False] * (n + 1)
        dp[0] = True
        for i in range(2, n + 1):
            if dp[i - 2] and nums[i - 1] == nums[i - 2]:
                dp[i] = True
            if i >= 3:
                if dp[i - 3] and nums[i - 1] == nums[i - 2] == nums[i - 3]:
                    dp[i] = True
                if dp[i - 3] and nums[i - 1] - nums[i - 2] == 1 and nums[i - 2] - nums[i - 3] == 1:
                    dp[i] = True
        return dp[n]

